 4→
 5→/// <summary>
 6→/// Middleware that reads or generates a correlation ID for each request,
 7→/// enriches the Serilog log context, and returns it in the response headers.
 8→/// </summary>
 9→public class CorrelationIdMiddleware
10→{
11→    public const string HeaderName = "X-Correlation-Id";
12→    private readonly RequestDelegate _next;
13→
14→    public CorrelationIdMiddleware(RequestDelegate next)
15→    {
16→        _next = next;
17→    }
18→
19→    public async Task InvokeAsync(HttpContext context)
20→    {
21→        var correlationId = GetOrGenerateCorrelationId(context);
22→
23→        // Store in HttpContext.Items so other components can access it
24→        context.Items["CorrelationId"] = correlationId;
25→
26→        // Add correlation ID to response headers
27→        context.Response.OnStarting(() =>
28→        {
29→            context.Response.Headers[HeaderName] = correlationId;
30→            return Task.CompletedTask;
31→        });
32→
33→        // Push correlation ID into Serilog's LogContext for all downstream log entries
34→        using (LogContext.PushProperty("CorrelationId", correlationId))
35→        {
